package org.R4ZXRN3T.wfmarketapi;

import org.R4ZXRN3T.wfmarketapi.objects.datamodels.Localization;

public class Utils {
	public static String getLocalizedValue(Localization i18n, Localization.Language language, Localization.LocalizedField field) {
		if (i18n == null) {
			return null;
		}

		Localization.LocaleData localeData = i18n.getLanguageData(language);
		if (localeData == null && language != Localization.Language.ENGLISH) {
			localeData = i18n.getLanguageData(Localization.Language.ENGLISH);
		}
		if (localeData == null) {
			return null;
		}

		switch (field) {
			case NAME:
				return localeData.getName();
			case DESCRIPTION:
				return localeData.getDescription();
			case WIKI_LINK:
				return localeData.getWikiLink();
			case ICON:
				return localeData.getIcon();
			case THUMB:
				return localeData.getThumb();
			case SUB_ICON:
				return localeData.getSubIcon();
			default:
				return null;
		}
	}
}

package org.R4ZXRN3T.wfmarketapi;

import org.R4ZXRN3T.wfmarketapi.objects.datamodels.Localization;

/**
 * Small utility helpers used by the library.
 */
public class Utils {
	/**
	 * Selects a localized value from a {@link Localization} container.
	 * Falls back to English when the requested language is not available.
	 *
	 * @param i18n the localization container
	 * @param language preferred language
	 * @param field field to retrieve
	 * @return localized string or null
	 */
	public static String getLocalizedValue(Localization i18n, Localization.Language language, Localization.LocalizedField field) {
		if (i18n == null) {
			return null;
		}

		Localization.LocaleData localeData = i18n.getLanguageData(language);
		if (localeData == null && language != Localization.Language.ENGLISH) {
			localeData = i18n.getLanguageData(Localization.Language.ENGLISH);
		}
		if (localeData == null) {
			return null;
		}

		switch (field) {
			case NAME:
				return localeData.getName();
			case DESCRIPTION:
				return localeData.getDescription();
			case WIKI_LINK:
				return localeData.getWikiLink();
			case ICON:
				return localeData.getIcon();
			case THUMB:
				return localeData.getThumb();
			case SUB_ICON:
				return localeData.getSubIcon();
			default:
				return null;
		}
	}
}

package org.R4ZXRN3T.wfmarketapi.objects.datamodels;

public class Achievement extends DataModel {
    public static class AchievementState {
        private Boolean featured;
        private Boolean hidden;
        private Integer progress;
        private String completedAt;

        public AchievementState() {
            this.featured = null;
            this.hidden = null;
            this.progress = null;
            this.completedAt = null;
        }

        public AchievementState(Boolean featured, Boolean hidden, Integer progress, String completedAt) {
            this.featured = featured;
            this.hidden = hidden;
            this.progress = progress;
            this.completedAt = completedAt;
        }

        public Boolean getFeatured() {
            return featured;
        }

        public void setFeatured(Boolean featured) {
            this.featured = featured;
        }

        public Boolean getHidden() {
            return hidden;
        }

        public void setHidden(Boolean hidden) {
            this.hidden = hidden;
        }

        public Integer getProgress() {
            return progress;
        }

        public void setProgress(Integer progress) {
            this.progress = progress;
        }

        public String getCompletedAt() {
            return completedAt;
        }

        public void setCompletedAt(String completedAt) {
            this.completedAt = completedAt;
        }
    }

    private String id;
    private String slug;
    private String type;
    private Boolean secret;
    private Integer reputationBonus;
    private Integer goal;
    private Localization i18n;
    private AchievementState state;

    public Achievement() {
        this.id = null;
        this.slug = null;
        this.type = null;
        this.secret = null;
        this.reputationBonus = null;
        this.goal = null;
        this.i18n = null;
        this.state = null;
    }

    public Achievement(String id, String slug, String type, Boolean secret, Integer reputationBonus, Integer goal, Localization i18n, AchievementState state) {
        this.id = id;
        this.slug = slug;
        this.type = type;
        this.secret = secret;
        this.reputationBonus = reputationBonus;
        this.goal = goal;
        this.i18n = i18n;
        this.state = state;
    }

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public String getSlug() {
        return slug;
    }

    public void setSlug(String slug) {
        this.slug = slug;
    }

    public String getType() {
        return type;
    }

    public void setType(String type) {
        this.type = type;
    }

    public Boolean getSecret() {
        return secret;
    }

    public void setSecret(Boolean secret) {
        this.secret = secret;
    }

    public Integer getReputationBonus() {
        return reputationBonus;
    }

    public void setReputationBonus(Integer reputationBonus) {
        this.reputationBonus = reputationBonus;
    }

    public Integer getGoal() {
        return goal;
    }

    public void setGoal(Integer goal) {
        this.goal = goal;
    }

    public Localization getI18n() {
        return i18n;
    }

    public void setI18n(Localization i18n) {
        this.i18n = i18n;
    }

    public AchievementState getState() {
        return state;
    }

    public void setState(AchievementState state) {
        this.state = state;
    }
}

package org.R4ZXRN3T.wfmarketapi.objects.datamodels;

/**
 * Achievement metadata and state container.
 */
public class Achievement extends DataModel {
    /**
     * Embedded state for an achievement (user-specific progress/flags).
     */
    public static class AchievementState {
        private Boolean featured;
        private Boolean hidden;
        private Integer progress;
        private String completedAt;

        /** No-arg constructor (fields set to null). */
        public AchievementState() {
            this.featured = null;
            this.hidden = null;
            this.progress = null;
            this.completedAt = null;
        }

        /** All-args constructor. */
        public AchievementState(Boolean featured, Boolean hidden, Integer progress, String completedAt) {
            this.featured = featured;
            this.hidden = hidden;
            this.progress = progress;
            this.completedAt = completedAt;
        }

        /** Returns whether this achievement is featured. */
        public Boolean getFeatured() {
            return featured;
        }

        /** Sets featured flag. */
        public void setFeatured(Boolean featured) {
            this.featured = featured;
        }

        /** Returns hidden flag. */
        public Boolean getHidden() {
            return hidden;
        }

        /** Sets hidden flag. */
        public void setHidden(Boolean hidden) {
            this.hidden = hidden;
        }

        /** Returns progress value. */
        public Integer getProgress() {
            return progress;
        }

        /** Sets progress value. */
        public void setProgress(Integer progress) {
            this.progress = progress;
        }

        /** Returns completed-at timestamp. */
        public String getCompletedAt() {
            return completedAt;
        }

        /** Sets completed-at timestamp. */
        public void setCompletedAt(String completedAt) {
            this.completedAt = completedAt;
        }
    }

    private String id;
    private String slug;
    private String type;
    private Boolean secret;
    private Integer reputationBonus;
    private Integer goal;
    private Localization i18n;
    private AchievementState state;

    /** No-arg constructor. */
    public Achievement() {
        this.id = null;
        this.slug = null;
        this.type = null;
        this.secret = null;
        this.reputationBonus = null;
        this.goal = null;
        this.i18n = null;
        this.state = null;
    }

    /** All-args constructor. */
    public Achievement(String id, String slug, String type, Boolean secret, Integer reputationBonus, Integer goal, Localization i18n, AchievementState state) {
        this.id = id;
        this.slug = slug;
        this.type = type;
        this.secret = secret;
        this.reputationBonus = reputationBonus;
        this.goal = goal;
        this.i18n = i18n;
        this.state = state;
    }

    /** Returns achievement id. */
    public String getId() {
        return id;
    }

    /** Sets achievement id. */
    public void setId(String id) {
        this.id = id;
    }

    /** Returns slug. */
    public String getSlug() {
        return slug;
    }

    /** Sets slug. */
    public void setSlug(String slug) {
        this.slug = slug;
    }

    /** Returns type. */
    public String getType() {
        return type;
    }

    /** Sets type. */
    public void setType(String type) {
        this.type = type;
    }

    /** Returns secret flag. */
    public Boolean getSecret() {
        return secret;
    }

    /** Sets secret flag. */
    public void setSecret(Boolean secret) {
        this.secret = secret;
    }

    /** Returns reputation bonus. */
    public Integer getReputationBonus() {
        return reputationBonus;
    }

    /** Sets reputation bonus. */
    public void setReputationBonus(Integer reputationBonus) {
        this.reputationBonus = reputationBonus;
    }

    /** Returns goal value. */
    public Integer getGoal() {
        return goal;
    }

    /** Sets goal value. */
    public void setGoal(Integer goal) {
        this.goal = goal;
    }

    /** Returns localization container. */
    public Localization getI18n() {
        return i18n;
    }

    /** Sets localization container. */
    public void setI18n(Localization i18n) {
        this.i18n = i18n;
    }

    /** Returns achievement state. */
    public AchievementState getState() {
        return state;
    }

    /** Sets achievement state. */
    public void setState(AchievementState state) {
        this.state = state;
    }
}

