    UNKNOWN("unknown"),
    IDLE("idle"),
    ON_MISSION("on_mission"),
    IN_DOJO("dojo"),
    IN_ORBITER("orbiter"),
    IN_RELAY("relay");

    private final String value;

    ActivityType(String value) { this.value = value; }

    @Override
